# backend/tracking_api.py (FastAPI demo)
from fastapi import FastAPI, Request
from datetime import datetime

app = FastAPI()
REQUIRED = {'event', 'event_time', 'session_id', 'channel', 'campaign_id', 'vehicle_model', 'city', 'store_id'}

@app.post('/api/track')
async def track(request: Request):
    payload = await request.json()
    missing = [k for k in REQUIRED if k not in payload]
    if missing:
        return {'ok': False, 'error': f'missing fields: {missing}'}
    payload['server_time'] = datetime.utcnow().isoformat()
    print('[TRACK_EVENT]', payload)
    return {'ok': True}
